static bool transient_close_guard_active(void) {
    if (s_transient_close_guard_started_ms == 0) return false;
    return lv_tick_elaps(s_transient_close_guard_started_ms) < 500;
}

static bool programs_interaction_guard_active(void) {
    if (s_programs_interaction_guard_started_ms == 0 || s_programs_interaction_guard_duration_ms == 0) return false;
    return lv_tick_elaps(s_programs_interaction_guard_started_ms) < s_programs_interaction_guard_duration_ms;
}

void action_block_programs_interaction(uint32_t duration_ms) {
    if (duration_ms == 0) duration_ms = 1200;
    s_programs_interaction_guard_started_ms = lv_tick_get();
    s_programs_interaction_guard_duration_ms = duration_ms;
}

static bool ui_programs_screen_is_active(void) {
    if (ui_get_current_screen_id() != SCREEN_ID_PROGRAMS) return false;
    if (ui_is_navigation_active() || transient_close_guard_active() || programs_interaction_guard_active()) return false;
    if (!objects.programs) return false;
    return lv_scr_act() == objects.programs;
}

