static void ui_debug_count_tree(lv_obj_t *root, uint32_t *out_nodes, uint32_t *out_kb, uint32_t *out_bm, uint32_t *out_ta) {
    if (!root) return;
    enum { MAX_STACK = 96, MAX_NODES = 320 };
    lv_obj_t *stack[MAX_STACK];
    int sp = 0;
    stack[sp++] = root;
    while (sp > 0) {
        lv_obj_t *obj = stack[--sp];
        if (!obj) continue;

        if (out_nodes) {
            (*out_nodes)++;
            if (*out_nodes >= MAX_NODES) break;
        }

        if (lv_obj_check_type(obj, &lv_keyboard_class)) {
            if (out_kb) (*out_kb)++;
        } else if (lv_obj_check_type(obj, &lv_buttonmatrix_class)) {
            if (out_bm) (*out_bm)++;
        } else if (lv_obj_check_type(obj, &lv_textarea_class)) {
            if (out_ta) (*out_ta)++;
        }

        const uint32_t cc = lv_obj_get_child_count(obj);
        for (uint32_t i = 0; i < cc; i++) {
            lv_obj_t *child = lv_obj_get_child(obj, (int32_t)i);
            if (!child) break;
            if (sp < MAX_STACK) stack[sp++] = child;
        }
    }
}
