static void pp_obj_delete_async_safe(lv_obj_t **obj) {
    if (!obj || !*obj) return;
    if (!lv_obj_is_valid(*obj)) {
        *obj = NULL;
        return;
    }
    lv_indev_reset(NULL, NULL);
    lv_obj_delete_async(*obj);
    *obj = NULL;
}

static void pp_obj_delete_async_safe_event(lv_event_t *e, lv_obj_t **obj) {
    if (!obj || !*obj) return;
    if (!lv_obj_is_valid(*obj)) {
        *obj = NULL;
        return;
    }
    lv_indev_t *indev = e ? lv_event_get_indev(e) : NULL;
    if (indev) lv_indev_reset(indev, NULL);
    lv_indev_reset(NULL, NULL);
    lv_obj_delete_async(*obj);
    *obj = NULL;
}

