typedef struct {
    void (*delete_fn)(void);
    enum ScreensEnum screen_id;
} nav_delete_ctx_t;

static void nav_delete_and_request_async_cb(void *user_data) {
    nav_delete_ctx_t *ctx = (nav_delete_ctx_t *)user_data;
    if (!ctx) return;
    if (ctx->delete_fn) ctx->delete_fn();
    if (ctx->screen_id) requestScreen(ctx->screen_id);
    lv_free(ctx);
}

static void nav_delete_and_request_async(void (*delete_fn)(void), enum ScreensEnum screen_id) {
    nav_delete_ctx_t *ctx = (nav_delete_ctx_t *)lv_malloc(sizeof(nav_delete_ctx_t));
    if (!ctx) {
        if (delete_fn) delete_fn();
        requestScreen(screen_id);
        return;
    }
    ctx->delete_fn = delete_fn;
    ctx->screen_id = screen_id;
    (void)lv_async_call(nav_delete_and_request_async_cb, ctx);
}

