static void ui_keyboard_target_size(lv_coord_t *w, lv_coord_t *h) {
    lv_coord_t tw = 480;
    lv_coord_t th = 320;
    lv_display_t *disp = lv_display_get_default();
    if (disp) {
        const lv_coord_t dw = (lv_coord_t)lv_display_get_horizontal_resolution(disp);
        const lv_coord_t dh = (lv_coord_t)lv_display_get_vertical_resolution(disp);
        if (dw > 0) tw = dw;
        if (dh > 0) th = dh;
    }
    if (w) *w = tw;
    if (h) *h = th;
}

static void keyboard_close() {
    lv_obj_t *overlay = s_kb_overlay;
    lv_obj_t *kb = s_kb;
#if defined(ESP_PLATFORM)
    // #region debug-point settings-history-wdt-kb-close
    ESP_LOGI(s_dbg_tag_kb_flow,
             "keyboard_close: cur=%d nav=%d guard=%d overlay=%p ta=%p kb=%p target=%p step_active=%d step_idx=%u kind=%u programs_active=%d act=%p programs=%p",
             (int)ui_get_current_screen_id(),
             ui_is_navigation_active() ? 1 : 0,
             transient_close_guard_active() ? 1 : 0,
             (void *)s_kb_overlay,
             (void *)s_kb_ta,
             (void *)s_kb,
             (void *)s_kb_target,
             s_kb_step_active ? 1 : 0,
             (unsigned)s_kb_step_idx,
             (unsigned)s_kb_step_kind,
             ui_programs_screen_is_active() ? 1 : 0,
             (void *)lv_scr_act(),
             (void *)objects.programs);
    // #endregion
    action_debug_dump_overlay_state("keyboard_close:entry");
#endif
    s_kb_overlay = NULL;
    s_kb_ta = NULL;
    s_kb = NULL;
    s_kb_target = NULL;
    s_kb_back_lbl = NULL;
    s_kb_target_is_program_name = false;
    s_kb_use_affixes = false;
    s_kb_manual_input = false;
    s_kb_prefix[0] = '\0';
    s_kb_suffix[0] = '\0';
    s_kb_step_active = false;
    s_kb_step_idx = 0;
    s_kb_step_kind = 0;
    s_kb_lang_key_text[0] = '\0';
    s_kb_layout_ua = false;
#if defined(ESP_PLATFORM)
    // #region debug-point settings-history-panic-kb-pre-delete
    ESP_LOGI(s_dbg_tag_kb_flow,
             "keyboard_close: pre_delete overlay=%p kb=%p act=%p cur=%d nav=%d guard=%d programs=%p info=%p",
             (void *)overlay,
             (void *)kb,
             (void *)lv_scr_act(),
             (int)ui_get_current_screen_id(),
             ui_is_navigation_active() ? 1 : 0,
             transient_close_guard_active() ? 1 : 0,
             (void *)objects.programs,
             (void *)s_programs_ctx.info_sub);
    // #endregion
#endif
    if (kb && lv_obj_is_valid(kb)) {
        lv_keyboard_set_textarea(kb, NULL);
    }
    if (overlay && lv_obj_is_valid(overlay)) {
        lv_indev_reset(NULL, NULL);
        lv_obj_add_flag(overlay, LV_OBJ_FLAG_HIDDEN);
        lv_obj_delete(overlay);
    }
#if defined(ESP_PLATFORM)
    // #region debug-point settings-history-panic-kb-post-delete
    ESP_LOGI(s_dbg_tag_kb_flow,
             "keyboard_close: post_delete overlay=%p kb=%p act=%p cur=%d nav=%d guard=%d programs=%p info=%p",
             (void *)overlay,
             (void *)kb,
             (void *)lv_scr_act(),
             (int)ui_get_current_screen_id(),
             ui_is_navigation_active() ? 1 : 0,
             transient_close_guard_active() ? 1 : 0,
             (void *)objects.programs,
             (void *)s_programs_ctx.info_sub);
    // #endregion
    action_debug_dump_overlay_state("keyboard_close:post_delete");
#endif
}

void action_close_transient_overlays(void) {
#if defined(ESP_PLATFORM)
    // #region debug-point settings-history-wdt-close-overlays
    ESP_LOGI(s_dbg_tag_nav_race,
             "close_transient_overlays: nav=%d guard=%d kb_overlay=%p wifi_kb=%p wifi_popup=%p step_active=%d",
             ui_is_navigation_active() ? 1 : 0,
             transient_close_guard_active() ? 1 : 0,
             (void *)s_kb_overlay,
             (void *)s_wifi_kb_overlay,
             (void *)s_wifi_setup_popup,
             s_kb_step_active ? 1 : 0);
    // #endregion
    action_debug_dump_overlay_state("close_transient_overlays:entry");
#endif
    s_transient_close_guard_started_ms = lv_tick_get();
    action_block_programs_interaction(1200);
    if (s_kb_overlay) keyboard_close();
    if (s_wifi_kb_overlay) wifi_kb_close();
    if (s_wifi_setup_popup) wifi_setup_close_cb(NULL);
#if defined(ESP_PLATFORM)
    action_debug_dump_overlay_state("close_transient_overlays:exit");
#endif
}

static void keyboard_commit(void) {
    if (ui_is_navigation_active() || transient_close_guard_active()) {
        keyboard_close();
        return;
    }
    const bool on_programs_screen = ui_programs_screen_is_active();
    if (s_kb_ta) {
        const char *txt = lv_textarea_get_text(s_kb_ta);
        if (!txt) txt = "";
        if (s_kb_target_is_program_name) {
            ui_set_selected_program_name(txt);
            if (s_kb_target) lv_label_set_text(s_kb_target, ui_get_selected_program_name());
        } else if (s_kb_target) {
            if (s_kb_use_affixes) {
                char buf[128];
                lv_snprintf(buf, sizeof(buf), "%s%s%s", s_kb_prefix, txt, s_kb_suffix);
                lv_label_set_text(s_kb_target, buf);
            } else {
                lv_label_set_text(s_kb_target, txt);
            }
        }
    }
    if (on_programs_screen && s_kb_step_active && s_kb_target) {
        const uint8_t pid = ui_get_selected_program_id();
        const uint8_t id = (pid == 255) ? 255 : pid;

        const char *cur = lv_label_get_text(s_kb_target);
        if (!cur) cur = "";

        int16_t temp = ui_get_program_step_temp(id, s_kb_step_idx);
        uint16_t rate_x10 = ui_get_program_step_rate_c_per_h_x10(id, s_kb_step_idx);
        uint32_t hold_s = ui_get_program_step_hold_s(id, s_kb_step_idx);

        if (s_kb_step_kind == KB_KIND_TEMP) {
            temp = (int16_t)parse_int_prefix(cur);
        } else if (s_kb_step_kind == KB_KIND_NUMBER || s_kb_step_kind == KB_KIND_SPEED) {
            const float rate = parse_float_prefix(cur);
            const bool per_min = (strstr(cur, "/хв") != NULL) || (strstr(cur, "/min") != NULL) || (strstr(cur, "/m") != NULL);
            float per_h = per_min ? (rate * 60.0f) : rate;
            if (per_h < 0.0f) per_h = 0.0f;
            rate_x10 = (uint16_t)(per_h * 10.0f + 0.5f);
        } else if (s_kb_step_kind == KB_KIND_HOLD) {
            hold_s = parse_time_s_hms(cur);
        }

        ui_set_program_step(id, s_kb_step_idx, temp, rate_x10, hold_s);
    }
    if (on_programs_screen) programs_update_info();
    keyboard_close();
}

static void keyboard_event_cb(lv_event_t *e) {
    const lv_event_code_t code = lv_event_get_code(e);
    if (code == LV_EVENT_CANCEL) {
        keyboard_close();
        return;
    }
    if (code != LV_EVENT_READY) return;
    keyboard_commit();
}

static void keyboard_value_changed_cb(lv_event_t *e) {
    lv_obj_t *kb = lv_event_get_target(e);
    if (!kb) return;
    if (ui_is_navigation_active() || transient_close_guard_active()) {
        keyboard_close();
        return;
    }

    const uint32_t btn_id = lv_buttonmatrix_get_selected_button(kb);
    if (btn_id == LV_BUTTONMATRIX_BUTTON_NONE) return;

    const char *txt = lv_buttonmatrix_get_button_text(kb, btn_id);
    if (!txt || txt[0] == '\0') return;
    if (strcmp(txt, "\n") == 0) return;

    if (strcmp(txt, "UA") == 0 || strcmp(txt, "EN") == 0) {
        const lv_keyboard_mode_t cur_mode = lv_keyboard_get_mode(kb);
        s_kb_layout_ua = !s_kb_layout_ua;
        lv_snprintf(s_kb_lang_key_text, sizeof(s_kb_lang_key_text), "%s", s_kb_layout_ua ? "EN" : "UA");

        lv_keyboard_set_map(kb, LV_KEYBOARD_MODE_TEXT_LOWER, s_kb_layout_ua ? s_kb_map_ua_lc : s_kb_map_text_lc,
                            s_kb_layout_ua ? s_kb_ctrl_ua_lc : s_kb_ctrl_text_lc);
        lv_keyboard_set_map(kb, LV_KEYBOARD_MODE_TEXT_UPPER, s_kb_layout_ua ? s_kb_map_ua_uc : s_kb_map_text_uc,
                            s_kb_layout_ua ? s_kb_ctrl_ua_uc : s_kb_ctrl_text_uc);
        lv_keyboard_set_mode(kb, cur_mode);
        lv_event_stop_processing(e);
        return;
    }

    if (!s_kb_manual_input || !s_kb_ta) return;

    if (strcmp(txt, "DEL") == 0) {
        lv_textarea_delete_char(s_kb_ta);
        lv_event_stop_processing(e);
        return;
    }
    if (strcmp(txt, "X") == 0) {
        lv_textarea_set_text(s_kb_ta, "");
        lv_event_stop_processing(e);
        return;
    }
    if (strcmp(txt, "OK") == 0) {
        keyboard_commit();
        lv_event_stop_processing(e);
        return;
    }

    lv_textarea_add_text(s_kb_ta, txt);
    lv_event_stop_processing(e);
}

