static void split_value_text(const char *src, const char *allowed, char *prefix, size_t prefix_sz, char *value, size_t value_sz,
                             char *suffix, size_t suffix_sz) {
    if (!src) src = "";
    if (!allowed) allowed = "0123456789";
    if (prefix && prefix_sz) prefix[0] = '\0';
    if (value && value_sz) value[0] = '\0';
    if (suffix && suffix_sz) suffix[0] = '\0';

    size_t i = 0;
    while (src[i] != '\0') {
        const char c = src[i];
        bool ok = false;
        for (size_t k = 0; allowed[k] != '\0'; k++) {
            if (c == allowed[k]) {
                ok = true;
                break;
            }
        }
        if (ok) break;
        i++;
    }

    size_t j = i;
    while (src[j] != '\0') {
        const char c = src[j];
        bool ok = false;
        for (size_t k = 0; allowed[k] != '\0'; k++) {
            if (c == allowed[k]) {
                ok = true;
                break;
            }
        }
        if (!ok) break;
        j++;
    }

    if (prefix && prefix_sz) {
        const size_t n = (i < prefix_sz - 1) ? i : (prefix_sz - 1);
        memcpy(prefix, src, n);
        prefix[n] = '\0';
    }
    if (value && value_sz) {
        const size_t n = ((j - i) < value_sz - 1) ? (j - i) : (value_sz - 1);
        memcpy(value, src + i, n);
        value[n] = '\0';
    }
    if (suffix && suffix_sz) {
        const size_t len = strlen(src);
        if (j < len) {
            const size_t n = ((len - j) < suffix_sz - 1) ? (len - j) : (suffix_sz - 1);
            memcpy(suffix, src + j, n);
            suffix[n] = '\0';
        }
    }
}

static void keyboard_open_for_label(lv_obj_t *label, bool is_program_name, lv_keyboard_mode_t mode, const char *accepted_chars,
                                    bool use_affixes) {
    if (!label) return;
    if (!ui_programs_screen_is_active()) {
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_kb_flow,
                 "keyboard_open_for_label: skip reason=programs_inactive cur=%d nav=%d guard=%d programs_guard=%d label=%p act=%p programs=%p",
                 (int)ui_get_current_screen_id(),
                 ui_is_navigation_active() ? 1 : 0,
                 transient_close_guard_active() ? 1 : 0,
                 programs_interaction_guard_active() ? 1 : 0,
                 (void *)label,
                 (void *)lv_scr_act(),
                 (void *)objects.programs);
#endif
        return;
    }
#if defined(ESP_PLATFORM)
    const uint32_t dbg_begin_ms = lv_tick_get();
    ESP_LOGI(s_dbg_tag_kb_flow,
             "keyboard_open_for_label: cur=%d nav=%d guard=%d label=%p label_parent=%p label_parent_kind=%s prog_name=%d mode=%d affixes=%d overlay=%p accepted=%s",
             (int)ui_get_current_screen_id(),
             ui_is_navigation_active() ? 1 : 0,
             transient_close_guard_active() ? 1 : 0,
             (void *)label,
             (void *)lv_obj_get_parent(label),
             ui_debug_obj_kind(lv_obj_get_parent(label)),
             is_program_name ? 1 : 0,
             (int)mode,
             use_affixes ? 1 : 0,
             (void *)s_kb_overlay,
             accepted_chars ? accepted_chars : "(null)");
#endif
    if (s_kb_overlay) keyboard_close();

    lv_coord_t sw = 480;
    lv_coord_t sh = 320;
    ui_keyboard_target_size(&sw, &sh);
    if (sw < 320) sw = 320;
    if (sh < 240) sh = 240;
    const lv_coord_t margin = 10;
    const lv_coord_t gap = 8;
    const lv_coord_t header_h = 44;
    const lv_coord_t back_w = 110;
    const lv_coord_t ta_w = (lv_coord_t)(sw - 2 * margin - gap - back_w);
    const lv_coord_t kb_y = (lv_coord_t)(margin + header_h + gap);

    s_kb_target = label;
    s_kb_target_is_program_name = is_program_name;
    s_kb_use_affixes = use_affixes;

    s_kb_overlay = lv_obj_create(lv_layer_top());
    lv_obj_remove_style_all(s_kb_overlay);
    lv_obj_set_size(s_kb_overlay, lv_pct(100), lv_pct(100));
    lv_obj_set_style_bg_color(s_kb_overlay, lv_color_hex(0xff090c10), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_bg_opa(s_kb_overlay, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_clear_flag(s_kb_overlay, LV_OBJ_FLAG_SCROLLABLE);

    lv_obj_t *panel = lv_obj_create(s_kb_overlay);
    lv_obj_set_pos(panel, 0, 0);
    lv_obj_set_size(panel, sw, sh);
    lv_obj_set_style_bg_opa(panel, LV_OPA_TRANSP, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_border_width(panel, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_pad_all(panel, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_clear_flag(panel, LV_OBJ_FLAG_SCROLLABLE);

    const bool compact = (mode == LV_KEYBOARD_MODE_USER_1) || (mode == LV_KEYBOARD_MODE_USER_2) || (mode == LV_KEYBOARD_MODE_USER_3);
    s_kb_manual_input = compact;
    s_kb_layout_ua = !ui_is_english();

    lv_obj_t *btn_back = lv_btn_create(panel);
    lv_obj_set_pos(btn_back, (lv_coord_t)(sw - margin - back_w), margin);
    lv_obj_set_size(btn_back, back_w, header_h);
    lv_obj_set_style_bg_color(btn_back, lv_color_hex(0xff0e131f), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_bg_opa(btn_back, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_border_color(btn_back, lv_color_hex(0xff1c2538), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_border_width(btn_back, 1, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_radius(btn_back, 10, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_add_event_cb(btn_back, kb_back_cb, LV_EVENT_CLICKED, NULL);
    {
        lv_obj_t *lbl = lv_label_create(btn_back);
        lv_obj_set_style_text_font(lbl, &font_4305a60a491c803d80080d015637c7d0, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_color(lbl, lv_color_hex(0xff7a8b9e), LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_label_set_text(lbl, ui_is_english() ? "BACK" : "НАЗАД");
        lv_obj_center(lbl);
        s_kb_back_lbl = lbl;
    }

    s_kb_ta = lv_textarea_create(panel);
    lv_obj_set_align(s_kb_ta, LV_ALIGN_TOP_LEFT);
    lv_obj_set_pos(s_kb_ta, margin, margin);
    lv_obj_set_size(s_kb_ta, ta_w, header_h);
    lv_obj_set_style_text_font(s_kb_ta, &font_4305a60a491c803d80080d0337447350, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_color(s_kb_ta, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_bg_color(s_kb_ta, lv_color_hex(0xff090c10), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_bg_opa(s_kb_ta, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_border_color(s_kb_ta, lv_color_hex(0xff1c2538), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_border_width(s_kb_ta, 1, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_radius(s_kb_ta, 10, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_textarea_set_one_line(s_kb_ta, true);
    lv_textarea_set_max_length(s_kb_ta, 64);
    if (accepted_chars) lv_textarea_set_accepted_chars(s_kb_ta, accepted_chars);
    if (use_affixes) {
        char val[64];
        split_value_text(lv_label_get_text(label), accepted_chars, s_kb_prefix, sizeof(s_kb_prefix), val, sizeof(val), s_kb_suffix,
                         sizeof(s_kb_suffix));
        lv_textarea_set_text(s_kb_ta, val);
    } else {
        lv_textarea_set_text(s_kb_ta, lv_label_get_text(label));
    }

    s_kb = lv_keyboard_create(panel);
    lv_obj_set_align(s_kb, LV_ALIGN_TOP_LEFT);
    if (compact) {
        lv_obj_set_pos(s_kb, margin, kb_y);
        lv_obj_set_size(s_kb, (lv_coord_t)(sw - 2 * margin), (lv_coord_t)(sh - kb_y - margin));
        if (!s_kb_items_font_inited) {
            memcpy(&s_kb_items_font, LV_FONT_DEFAULT, sizeof(s_kb_items_font));
            s_kb_items_font.fallback = &font_4305a60a491c803d80080d015637c7d0;
            s_kb_items_font_inited = true;
        }
        lv_obj_set_style_text_font(s_kb, &s_kb_items_font, LV_PART_ITEMS | LV_STATE_DEFAULT);
        lv_obj_set_style_pad_row(s_kb, 4, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_pad_column(s_kb, 4, LV_PART_MAIN | LV_STATE_DEFAULT);
    } else {
        lv_obj_set_pos(s_kb, margin, kb_y);
        lv_obj_set_size(s_kb, (lv_coord_t)(sw - 2 * margin), (lv_coord_t)(sh - kb_y - margin));
        if (!s_kb_items_font_inited) {
            memcpy(&s_kb_items_font, LV_FONT_DEFAULT, sizeof(s_kb_items_font));
            s_kb_items_font.fallback = &font_4305a60a491c803d80080d015637c7d0;
            s_kb_items_font_inited = true;
        }
        lv_obj_set_style_text_font(s_kb, &s_kb_items_font, LV_PART_ITEMS | LV_STATE_DEFAULT);
        lv_obj_set_style_pad_row(s_kb, 3, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_pad_column(s_kb, 3, LV_PART_MAIN | LV_STATE_DEFAULT);
    }
    if (!compact) {
        lv_keyboard_set_textarea(s_kb, s_kb_ta);
    }
    lv_snprintf(s_kb_lang_key_text, sizeof(s_kb_lang_key_text), "%s", s_kb_layout_ua ? "EN" : "UA");
    lv_keyboard_set_mode(s_kb, mode);
    lv_keyboard_set_popovers(s_kb, false);
    lv_keyboard_set_map(s_kb, LV_KEYBOARD_MODE_TEXT_LOWER, s_kb_layout_ua ? s_kb_map_ua_lc : s_kb_map_text_lc,
                        s_kb_layout_ua ? s_kb_ctrl_ua_lc : s_kb_ctrl_text_lc);
    lv_keyboard_set_map(s_kb, LV_KEYBOARD_MODE_TEXT_UPPER, s_kb_layout_ua ? s_kb_map_ua_uc : s_kb_map_text_uc,
                        s_kb_layout_ua ? s_kb_ctrl_ua_uc : s_kb_ctrl_text_uc);
    lv_keyboard_set_map(s_kb, LV_KEYBOARD_MODE_SPECIAL, s_kb_map_spec, s_kb_ctrl_spec);
    lv_keyboard_set_map(s_kb, LV_KEYBOARD_MODE_NUMBER, s_kb_map_num, s_kb_ctrl_num);
    lv_keyboard_set_map(s_kb, LV_KEYBOARD_MODE_USER_1, s_kb_map_time, s_kb_ctrl_time);
    lv_keyboard_set_map(s_kb, LV_KEYBOARD_MODE_USER_2, s_kb_map_number, s_kb_ctrl_number);
    lv_keyboard_set_map(s_kb, LV_KEYBOARD_MODE_USER_3, s_kb_map_decimal, s_kb_ctrl_decimal);
    lv_obj_add_event_cb(s_kb, keyboard_value_changed_cb, (lv_event_code_t)(LV_EVENT_VALUE_CHANGED | LV_EVENT_PREPROCESS), NULL);
    lv_obj_add_event_cb(s_kb, keyboard_event_cb, LV_EVENT_READY, NULL);
    lv_obj_add_event_cb(s_kb, keyboard_event_cb, LV_EVENT_CANCEL, NULL);
#if defined(ESP_PLATFORM)
    // #region debug-point calibration-nav-keyboard-open
    ESP_LOGI(s_dbg_tag_nav_race,
             "keyboard_open_for_label: done dt_ms=%lu overlay=%p ta=%p kb=%p manual=%d",
             (unsigned long)lv_tick_elaps(dbg_begin_ms),
             (void *)s_kb_overlay,
             (void *)s_kb_ta,
             (void *)s_kb,
             s_kb_manual_input ? 1 : 0);
    // #endregion
    action_debug_dump_overlay_state("keyboard_open:done");
#endif
}

