static int32_t parse_int_prefix(const char *s) {
    if (!s) return 0;
    int32_t sign = 1;
    while (*s == ' ') s++;
    if (*s == '-') {
        sign = -1;
        s++;
    }
    int32_t v = 0;
    bool any = false;
    while (*s) {
        if (*s >= '0' && *s <= '9') {
            any = true;
            v = (v * 10) + (*s - '0');
        } else if (any) {
            break;
        }
        s++;
    }
    return v * sign;
}

static float parse_float_prefix(const char *s) {
    if (!s) return 0.0f;
    while (*s == ' ') s++;
    float sign = 1.0f;
    if (*s == '-') {
        sign = -1.0f;
        s++;
    }
    float v = 0.0f;
    bool any = false;
    while (*s) {
        if (*s >= '0' && *s <= '9') {
            any = true;
            v = (v * 10.0f) + (float)(*s - '0');
        } else if (*s == '.' || *s == ',') {
            s++;
            float mul = 0.1f;
            while (*s >= '0' && *s <= '9') {
                any = true;
                v += (float)(*s - '0') * mul;
                mul *= 0.1f;
                s++;
            }
            break;
        } else if (any) {
            break;
        }
        s++;
    }
    return v * sign;
}

static uint32_t parse_time_s_hms(const char *s) {
    if (!s) return 0;
    int parts[3] = { 0, 0, 0 };
    int p = 0;
    const char *cur = s;
    while (*cur && p < 3) {
        if ((*cur >= '0' && *cur <= '9') || *cur == '-') {
            parts[p] = (int)parse_int_prefix(cur);
            while (*cur && *cur != ':') cur++;
            if (*cur == ':') cur++;
            p++;
        } else {
            cur++;
        }
    }
    if (p == 0) return 0;
    int h = 0, m = 0, sec = 0;
    if (p == 1) {
        m = parts[0];
    } else if (p == 2) {
        h = parts[0];
        m = parts[1];
    } else {
        h = parts[0];
        m = parts[1];
        sec = parts[2];
    }
    if (h < 0) h = 0;
    if (m < 0) m = 0;
    if (sec < 0) sec = 0;
    return (uint32_t)(h * 3600 + m * 60 + sec);
}

static void fmt_hms(uint32_t sec, char *out, size_t out_sz) {
    const uint32_t h = sec / 3600;
    const uint32_t m = (sec % 3600) / 60;
    const uint32_t s2 = sec % 60;
    lv_snprintf(out, out_sz, "%u:%02u:%02u", (unsigned)h, (unsigned)m, (unsigned)s2);
}

static void programs_capture_selected(uint8_t dst_program_id, uint8_t src_program_id) {
    const uint16_t steps = ui_get_selected_program_steps_total();
    const uint16_t capped = (steps > 50) ? 50 : steps;
    for (uint16_t i = 0; i < capped; i++) {
        ui_set_program_step(dst_program_id,
                            i,
                            ui_get_program_step_temp(src_program_id, i),
                            ui_get_program_step_rate_c_per_h_x10(src_program_id, i),
                            ui_get_program_step_hold_s(src_program_id, i));
    }
    for (uint16_t i = capped; i < 50; i++) {
        ui_set_program_step(dst_program_id, i, 0, 0, 0);
    }
    ui_set_program_total_time_s(dst_program_id, ui_get_selected_program_total_time_s());
}

static void programs_update_info() {
    if (!ui_programs_screen_is_active()) {
#if defined(ESP_PLATFORM)
        // #region debug-point settings-calibration-programs-info
        ESP_LOGI(s_dbg_tag_kb_flow,
                 "programs_update_info: skip reason=screen_inactive cur=%d nav=%d guard=%d programs_guard=%d act=%p programs=%p info=%p",
                 (int)ui_get_current_screen_id(),
                 ui_is_navigation_active() ? 1 : 0,
                 transient_close_guard_active() ? 1 : 0,
                 programs_interaction_guard_active() ? 1 : 0,
                 (void *)lv_scr_act(),
                 (void *)objects.programs,
                 (void *)s_programs_ctx.info_sub);
        // #endregion
#endif
        return;
    }
    if (!s_programs_ctx.info_sub) {
#if defined(ESP_PLATFORM)
        // #region debug-point settings-calibration-programs-info
        ESP_LOGI(s_dbg_tag_kb_flow, "programs_update_info: skip reason=no_info_sub cur=%d act=%p programs=%p",
                 (int)ui_get_current_screen_id(), (void *)lv_scr_act(), (void *)objects.programs);
        // #endregion
#endif
        return;
    }
    if (!lv_obj_is_valid(s_programs_ctx.info_sub)) {
#if defined(ESP_PLATFORM)
        // #region debug-point settings-calibration-programs-info
        ESP_LOGI(s_dbg_tag_kb_flow, "programs_update_info: invalid info_sub=%p list=%p",
                 (void *)s_programs_ctx.info_sub, (void *)s_programs_ctx.list);
        // #endregion
#endif
        s_programs_ctx.list = NULL;
        s_programs_ctx.info_sub = NULL;
        return;
    }
#if defined(ESP_PLATFORM)
    // #region debug-point add-step-info
    const uint32_t info_begin_ms = lv_tick_get();
    // #endregion
#endif
    programs_update_info_from_model(ui_get_selected_program_steps_total());
#if defined(ESP_PLATFORM)
    // #region debug-point add-step-info
    ESP_LOGI(s_dbg_tag_add_step,
             "info done dt=%lu since_press=%lu since_async=%lu",
             (unsigned long)(lv_tick_get() - info_begin_ms),
             (unsigned long)(s_programs_add_step_press_ms ? (lv_tick_get() - s_programs_add_step_press_ms) : 0),
             (unsigned long)(s_programs_add_step_async_ms ? (lv_tick_get() - s_programs_add_step_async_ms) : 0));
    // #endregion
#endif
}

static void programs_reindex() {
    if (!s_programs_ctx.list) return;
    if (!lv_obj_is_valid(s_programs_ctx.list)) {
        s_programs_ctx.list = NULL;
        s_programs_ctx.info_sub = NULL;
        return;
    }
    const uint32_t cnt = lv_obj_get_child_count(s_programs_ctx.list);
    if (cnt == 0) return;
    for (uint32_t i = 0; i < cnt; i++) {
        if ((i % 4) == 0) PP_ACTIONS_YIELD();
        lv_obj_t *row = lv_obj_get_child(s_programs_ctx.list, i);
        if (!row) continue;
        lv_obj_t *idx = lv_obj_get_child(row, 1);
        if (!idx) continue;
        char buf[8];
        lv_snprintf(buf, sizeof(buf), "%u", (unsigned)(i + 1));
        const char *cur = lv_label_get_text(idx);
        if (!cur || strcmp(cur, buf) != 0) {
            lv_label_set_text(idx, buf);
        }
    }
    PP_ACTIONS_YIELD();
    programs_update_info();
    ui_set_selected_program_steps_total((uint16_t)cnt);
    const uint8_t pid = ui_get_selected_program_id();
    if (pid != 255) ui_set_program_steps_total(pid, (uint16_t)cnt);
}

