    lv_obj_set_style_text_align(h, LV_TEXT_ALIGN_CENTER, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_font(h, &font_4305a60a491c803d80080d015637c7d0, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_color(h, lv_color_hex(0xff00b761), LV_PART_MAIN | LV_STATE_DEFAULT);
