    lv_obj_set_size(trash, 56, 48);
    lv_obj_set_style_bg_color(trash, lv_color_hex(0xff421212), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_bg_opa(trash, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
