static void confirm_overlay_fullscreen(lv_obj_t *overlay) {
    if (!overlay) return;
    lv_coord_t sw = 480;
    lv_coord_t sh = 320;
    lv_display_t *disp = lv_display_get_default();
    if (disp) {
        const lv_coord_t dw = (lv_coord_t)lv_display_get_horizontal_resolution(disp);
        const lv_coord_t dh = (lv_coord_t)lv_display_get_vertical_resolution(disp);
        if (dw > 0) sw = dw;
        if (dh > 0) sh = dh;
    }
    lv_obj_set_pos(overlay, 0, 0);
    lv_obj_set_size(overlay, sw, sh);
    lv_obj_update_layout(overlay);
}

static void confirm_panel_layout(lv_obj_t *panel, lv_obj_t *txt, lv_obj_t *btn_cancel, lv_obj_t *btn_ok) {
    if (!panel) return;

    lv_obj_t *parent = lv_obj_get_parent(panel);
    lv_coord_t sw = parent ? lv_obj_get_width(parent) : 0;
    lv_coord_t sh = parent ? lv_obj_get_height(parent) : 0;
    if (sw <= 0 || sh <= 0) {
        lv_display_t *disp = lv_display_get_default();
        if (disp) {
            const lv_coord_t dw = (lv_coord_t)lv_display_get_horizontal_resolution(disp);
            const lv_coord_t dh = (lv_coord_t)lv_display_get_vertical_resolution(disp);
            if (dw > 0) sw = dw;
            if (dh > 0) sh = dh;
        }
    }
    if (sw <= 0) sw = 480;
    if (sh <= 0) sh = 320;

    style_flat_panel(panel, lv_color_hex(0xff0e131f), lv_color_hex(0xff1c2538), 1, 16, 16);
    lv_coord_t margin_x = (lv_coord_t)LV_MAX(24, (lv_coord_t)(sw / 12));
    lv_coord_t margin_y = (lv_coord_t)LV_MAX(24, (lv_coord_t)(sh / 10));
    if ((lv_coord_t)(margin_x * 2) > (lv_coord_t)(sw - 40)) margin_x = (lv_coord_t)LV_MAX(20, (lv_coord_t)((sw - 40) / 2));
    if ((lv_coord_t)(margin_y * 2) > (lv_coord_t)(sh - 40)) margin_y = (lv_coord_t)LV_MAX(20, (lv_coord_t)((sh - 40) / 2));
    const lv_coord_t panel_w = (lv_coord_t)LV_MAX(220, (lv_coord_t)(sw - (margin_x * 2)));
    const lv_coord_t panel_h = (lv_coord_t)LV_MAX(160, (lv_coord_t)(sh - (margin_y * 2)));
    lv_obj_set_size(panel, panel_w, panel_h);
    lv_obj_set_pos(panel, (lv_coord_t)((sw - panel_w) / 2), (lv_coord_t)((sh - panel_h) / 2));
    const lv_coord_t side_pad = (lv_coord_t)LV_MAX(16, panel_w / 18);
    const lv_coord_t top_pad = (lv_coord_t)LV_MAX(18, panel_h / 10);
    const lv_coord_t bottom_pad = (lv_coord_t)LV_MAX(14, panel_h / 12);
    const lv_coord_t btn_gap = (lv_coord_t)LV_MAX(12, panel_w / 22);
    const lv_coord_t btn_h = (lv_coord_t)LV_MAX(54, panel_h / 5);
    const lv_coord_t btn_w = (lv_coord_t)((panel_w - (side_pad * 2) - btn_gap) / 2);
    const lv_coord_t btn_y = (lv_coord_t)(panel_h - bottom_pad - btn_h);

    if (txt) {
        lv_obj_set_pos(txt, side_pad, top_pad);
        lv_obj_set_size(txt, (lv_coord_t)(panel_w - side_pad * 2), (lv_coord_t)LV_MAX(52, btn_y - top_pad - 10));
        lv_obj_set_style_text_color(txt, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_align(txt, LV_TEXT_ALIGN_CENTER, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_font(txt, &font_4305a60a491c803d80080d015637c7d0, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_obj_set_style_text_line_space(txt, 3, LV_PART_MAIN | LV_STATE_DEFAULT);
        lv_label_set_long_mode(txt, LV_LABEL_LONG_WRAP);
        lv_obj_clear_flag(txt, LV_OBJ_FLAG_HIDDEN);
    }

    if (btn_cancel) {
        lv_obj_set_pos(btn_cancel, side_pad, btn_y);
        lv_obj_set_size(btn_cancel, btn_w, btn_h);
        lv_obj_clear_flag(btn_cancel, LV_OBJ_FLAG_HIDDEN);
    }

    if (btn_ok) {
        lv_obj_set_pos(btn_ok, (lv_coord_t)(side_pad + btn_w + btn_gap), btn_y);
        lv_obj_set_size(btn_ok, btn_w, btn_h);
        lv_obj_clear_flag(btn_ok, LV_OBJ_FLAG_HIDDEN);
    }
}

static void start_firing_now(void) {
    const int code = kiln_ui_start_selected_program();
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_start_firing, "start_result: code=%d sel_id=%u sel_name='%s'",
             code, (unsigned)ui_get_selected_program_id(), ui_get_selected_program_name());
#endif
    if (code == 0) {
        toast_show(ui_is_english() ? "Started" : "Запущено");
        requestScreen(SCREEN_ID__1);
        return;
    }
    if (code == 13) {
        toast_show(ui_is_english() ? "No program selected" : "Не вибрано програму");
        return;
    }
    if (code == 14) {
        toast_show(ui_is_english() ? "Thermocouple error" : "Помилка термопари");
        return;
    }
    if (code == 16) {
        toast_show(ui_is_english() ? "Fault active" : "Активна помилка");
        return;
    }
    if (code == 17) {
        toast_show(ui_is_english() ? "Fan settings unsafe" : "Небезпечні налаштування вентилятора");
        return;
    }
    if (code == 18) {
        toast_show(ui_is_english() ? "Schedule exceeds max temp" : "Програма перевищує максимум температури");
        return;
    }
    if (code == 19) {
        toast_show(ui_is_english() ? "Clock not set" : "Годинник не налаштований");
        return;
    }
    if (code == 15) {
        toast_show(ui_is_english() ? "Touch not calibrated" : "Тач не відкалібрований");
        return;
    }
    toast_show(ui_is_english() ? "Start failed" : "Не вдалося запустити");
}

static void confirm_close(confirm_ctx_t *ctx) {
    if (!ctx) return;
    pp_obj_delete_async_safe(&ctx->overlay);
    lv_free(ctx);
}

static void confirm_prog_close(confirm_prog_ctx_t *ctx) {
    if (!ctx) return;
    pp_obj_delete_async_safe(&ctx->overlay);
    lv_free(ctx);
}

static void confirm_cancel_cb(lv_event_t *e) {
    confirm_ctx_t *ctx = (confirm_ctx_t *)lv_event_get_user_data(e);
    confirm_close(ctx);
}

static void confirm_prog_cancel_cb(lv_event_t *e) {
    confirm_prog_ctx_t *ctx = (confirm_prog_ctx_t *)lv_event_get_user_data(e);
#if defined(ESP_PLATFORM)
    // #region debug-point settings-history-wdt-confirm-prog-cancel
    ESP_LOGI(s_dbg_tag_nav_race,
             "confirm_prog_cancel_cb: nav=%d guard=%d overlay=%p program_id=%u",
             ui_is_navigation_active() ? 1 : 0, transient_close_guard_active() ? 1 : 0,
             ctx ? (void *)ctx->overlay : NULL, ctx ? (unsigned)ctx->program_id : 0U);
    // #endregion
#endif
    confirm_prog_close(ctx);
}

static void confirm_step_cancel_cb(lv_event_t *e) {
    confirm_step_ctx_t *ctx = (confirm_step_ctx_t *)lv_event_get_user_data(e);
    if (!ctx) return;
    pp_obj_delete_async_safe(&ctx->overlay);
    lv_free(ctx);
}

static void confirm_ok_cb(lv_event_t *e) {
    confirm_ctx_t *ctx = (confirm_ctx_t *)lv_event_get_user_data(e);
    if (ctx && ctx->row) {
        pp_obj_delete_async_safe_event(e, &ctx->row);
    }
    if (ctx) {
        pp_obj_delete_async_safe_event(e, &ctx->overlay);
    }
    (void)lv_async_call(programs_reindex_async_cb, NULL);
    if (ctx) lv_free(ctx);
}

static void confirm_prog_ok_cb(lv_event_t *e) {
    confirm_prog_ctx_t *ctx = (confirm_prog_ctx_t *)lv_event_get_user_data(e);
    if (!ctx) return;
    // #region debug-point program-delete-freeze
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_program_delete_freeze, "confirm_prog_ok_cb: id=%u count(before)=%u",
             (unsigned)ctx->program_id, (unsigned)ui_get_program_count());
#endif
    // #endregion
    const bool ok = ui_delete_program(ctx->program_id);
    // #region debug-point program-delete-freeze
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_program_delete_freeze, "ui_delete_program: ok=%d count(after)=%u sel=%u",
             (int)ok, (unsigned)ui_get_program_count(), (unsigned)ui_get_selected_program_id());
#endif
    // #endregion
    if (ok) {
        // #region debug-point program-delete-freeze
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_program_delete_freeze, "persist_save: begin");
#endif
        // #endregion
        ui_programs_persist_save();
        // #region debug-point program-delete-freeze
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_program_delete_freeze, "persist_save: end");
#endif
        // #endregion
        if (objects.programs_list != NULL) {
            screen_programs_list_refresh();
        } else {
            request_fresh_screen(SCREEN_ID_PROGRAMS_LIST);
        }
    }
    pp_obj_delete_async_safe_event(e, &ctx->overlay);
    lv_free(ctx);
}

static void confirm_step_ok_cb(lv_event_t *e) {
    confirm_step_ctx_t *ctx = (confirm_step_ctx_t *)lv_event_get_user_data(e);
    if (!ctx) return;

    const uint8_t pid = ui_get_selected_program_id();
    const uint8_t id = (pid == 255) ? 255 : pid;
    if (ui_program_delete_step(id, ctx->step)) {
        screen_programs_refresh_rows();
        programs_update_info();
    }

    pp_obj_delete_async_safe_event(e, &ctx->overlay);
    lv_free(ctx);
}

static void confirm_delete_row(lv_obj_t *row) {
    confirm_ctx_t *ctx = lv_malloc(sizeof(confirm_ctx_t));
    if (!ctx) return;
    ctx->row = row;
    ctx->overlay = lv_obj_create(lv_layer_top());
    lv_obj_remove_style_all(ctx->overlay);
    confirm_overlay_fullscreen(ctx->overlay);
    lv_obj_set_style_bg_color(ctx->overlay, lv_color_hex(0x000000), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_bg_opa(ctx->overlay, 160, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_clear_flag(ctx->overlay, LV_OBJ_FLAG_SCROLLABLE);

    lv_obj_t *panel = lv_obj_create(ctx->overlay);
    lv_obj_center(panel);

    lv_obj_t *txt = lv_label_create(panel);
    lv_label_set_text(txt, ui_is_english() ? "Delete this step?" : "Видалити цей крок?");

    lv_obj_t *btn_cancel = lv_btn_create(panel);
    style_flat_button(btn_cancel, lv_color_hex(0xff0e131f), 255, lv_color_hex(0xff1c2538), 1, 10);
    lv_obj_add_event_cb(btn_cancel, confirm_cancel_cb, LV_EVENT_CLICKED, ctx);
    lv_obj_t *lc = lv_label_create(btn_cancel);
    lv_obj_set_style_text_color(lc, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_font(lc, &font_4305a60a491c803d80080d05cbb3cac2, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(lc, ui_is_english() ? "Cancel" : "Скасувати");
    lv_obj_center(lc);

    lv_obj_t *btn_ok = lv_btn_create(panel);
    style_flat_button(btn_ok, lv_color_hex(0xff00b761), 255, lv_color_hex(0xff00b761), 0, 10);
    lv_obj_add_event_cb(btn_ok, confirm_ok_cb, LV_EVENT_CLICKED, ctx);
    lv_obj_t *lo = lv_label_create(btn_ok);
    lv_obj_set_style_text_color(lo, lv_color_hex(0xffffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_font(lo, &font_4305a60a491c803d80080d05cbb3cac2, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(lo, ui_is_english() ? "Confirm" : "Підтвердити");
    lv_obj_center(lo);

    confirm_panel_layout(panel, txt, btn_cancel, btn_ok);
}

