static void wifi_setup_update_pass_label(void) {
    if (!s_wifi_setup_pass_val) return;
    if (!s_wifi_setup_pass[0]) {
        lv_label_set_text(s_wifi_setup_pass_val, ui_is_english() ? "(not set)" : "(не вказано)");
        return;
    }
    const size_t n = strlen(s_wifi_setup_pass);
    static char mask[70];
    const size_t m = (n < sizeof(mask) - 1) ? n : (sizeof(mask) - 1);
    for (size_t i = 0; i < m; i++) mask[i] = '*';
    mask[m] = '\0';
    lv_label_set_text(s_wifi_setup_pass_val, mask);
}

static void wifi_kb_close_event(lv_event_t *e) {
    lv_obj_t *overlay = s_wifi_kb_overlay;
    lv_obj_t *kb = s_wifi_kb;
#if defined(ESP_PLATFORM)
    action_debug_dump_overlay_state("wifi_kb_close:entry");
#endif
    s_wifi_kb_overlay = NULL;
    s_wifi_kb_ta = NULL;
    s_wifi_kb = NULL;
    s_wifi_kb_kind = 0;
    if (kb && lv_obj_is_valid(kb)) {
        lv_keyboard_set_textarea(kb, NULL);
    }
    if (overlay && lv_obj_is_valid(overlay)) {
        lv_indev_reset(NULL, NULL);
        lv_obj_add_flag(overlay, LV_OBJ_FLAG_HIDDEN);
        if (e) pp_obj_delete_async_safe_event(e, &overlay);
        else lv_obj_delete(overlay);
    }
#if defined(ESP_PLATFORM)
    action_debug_dump_overlay_state("wifi_kb_close:exit");
#endif
}

static void wifi_kb_close(void) {
    wifi_kb_close_event(NULL);
}

static void wifi_kb_event_cb(lv_event_t *e) {
    const lv_event_code_t code = lv_event_get_code(e);
    if (code == LV_EVENT_CANCEL) {
        wifi_kb_close_event(e);
        return;
    }
    if (code != LV_EVENT_READY) return;
    const int kb_kind = s_wifi_kb_kind;
    const char *txt = (s_wifi_kb_ta) ? lv_textarea_get_text(s_wifi_kb_ta) : "";
    if (!txt) txt = "";
    if (s_wifi_kb_kind == 1) {
        strncpy(s_wifi_setup_pass, txt, sizeof(s_wifi_setup_pass) - 1);
        s_wifi_setup_pass[sizeof(s_wifi_setup_pass) - 1] = '\0';
        wifi_setup_update_pass_label();
    } else {
        strncpy(s_wifi_setup_ssid, txt, sizeof(s_wifi_setup_ssid) - 1);
        s_wifi_setup_ssid[sizeof(s_wifi_setup_ssid) - 1] = '\0';
        s_wifi_setup_auth = -1;
        wifi_setup_update_ssid_label();
    }
    wifi_setup_update_connect_enabled();
    wifi_kb_close_event(e);
    if (kb_kind == 1 && s_wifi_setup_auto_connect_after_pass) {
        s_wifi_setup_auto_connect_after_pass = false;
        wifi_setup_connect_cb(NULL);
    }
}

