static void wifi_setup_parse_scan_json(const char *json) {
    s_wifi_scan_count = 0;
    if (!json) return;
    const char *p = json;
    while (s_wifi_scan_count < WIFI_SCAN_MAX) {
        const char *k = strstr(p, "\"ssid\"");
        if (!k) break;
        const char *colon = strchr(k, ':');
        if (!colon) break;
        const char *q1 = strchr(colon, '"');
        if (!q1) break;
        q1++;
        const char *q2 = strchr(q1, '"');
        if (!q2) break;

        char ssid[33] = { 0 };
        const size_t ssid_len = (size_t)(q2 - q1);
        const size_t copy_len = (ssid_len < sizeof(ssid) - 1) ? ssid_len : (sizeof(ssid) - 1);
        memcpy(ssid, q1, copy_len);
        ssid[copy_len] = '\0';

        if (ssid[0] != '\0') {
            bool dup = false;
            for (int i = 0; i < s_wifi_scan_count; i++) {
                if (strcmp(s_wifi_scan_ssids[i], ssid) == 0) {
                    dup = true;
                    break;
                }
            }
            if (!dup) {
                int rssi = 0;
                int auth = -1;
                const char *end_obj = strchr(q2, '}');
                if (!end_obj) end_obj = q2;

                const char *kr = strstr(k, "\"rssi\"");
                if (kr && kr < end_obj) {
                    const char *cr = strchr(kr, ':');
                    if (cr) rssi = (int)strtol(cr + 1, NULL, 10);
                }
                const char *ka = strstr(k, "\"auth\"");
                if (ka && ka < end_obj) {
                    const char *ca = strchr(ka, ':');
                    if (ca) auth = (int)strtol(ca + 1, NULL, 10);
                }

                const size_t max_sz = sizeof(s_wifi_scan_ssids[s_wifi_scan_count]);
                size_t n = strlen(ssid);
                if (n >= max_sz) n = max_sz - 1;
                memcpy(s_wifi_scan_ssids[s_wifi_scan_count], ssid, n);
                s_wifi_scan_ssids[s_wifi_scan_count][n] = '\0';
                s_wifi_scan_rssi[s_wifi_scan_count] = rssi;
                s_wifi_scan_auth[s_wifi_scan_count] = auth;
                s_wifi_scan_count++;
            }
        }

        p = q2 + 1;
    }
}

