    lv_obj_t *subtitle = lv_label_create(s_wifi_setup_panel);
    lv_obj_set_width(subtitle, 692);
    lv_obj_set_style_text_align(subtitle, LV_TEXT_ALIGN_LEFT, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_font(subtitle, &font_4305a60a491c803d80080d0337447350, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_color(subtitle, lv_color_hex(0xff7a8b9e), LV_PART_MAIN | LV_STATE_DEFAULT);
