void action_open_keyboard(lv_event_t *e) {
    lv_obj_t *label = lv_event_get_target(e);
    const intptr_t kind = (intptr_t)lv_event_get_user_data(e);
#if defined(ESP_PLATFORM)
    // #region debug-point kiln-calibration-wdt-open-keyboard
    ESP_LOGI(s_dbg_tag_kb_flow,
             "action_open_keyboard: cur=%d target=%p kind=%ld parent=%p parent_kind=%s nav=%d guard=%d",
             (int)ui_get_current_screen_id(),
             (void *)label,
             (long)kind,
             label ? (void *)lv_obj_get_parent(label) : NULL,
             label ? ui_debug_obj_kind(lv_obj_get_parent(label)) : "null",
             ui_is_navigation_active() ? 1 : 0,
             transient_close_guard_active() ? 1 : 0);
    // #endregion
#endif
    if (!ui_programs_screen_is_active()) {
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_kb_flow,
                 "action_open_keyboard: skip reason=programs_inactive cur=%d nav=%d guard=%d programs_guard=%d target=%p act=%p programs=%p",
                 (int)ui_get_current_screen_id(),
                 ui_is_navigation_active() ? 1 : 0,
                 transient_close_guard_active() ? 1 : 0,
                 programs_interaction_guard_active() ? 1 : 0,
                 (void *)label,
                 (void *)lv_scr_act(),
                 (void *)objects.programs);
#endif
        return;
    }
    if (kind == KB_KIND_PROGRAM_NAME) {
        keyboard_open_for_label(label, true, LV_KEYBOARD_MODE_TEXT_LOWER, NULL, false);
        return;
    }
    if (kind == KB_KIND_TEMP) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_2, "0123456789", true);
        return;
    }
    if (kind == KB_KIND_HOLD) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_1, "0123456789:", true);
        return;
    }
    if (kind == KB_KIND_NUMBER) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_2, "0123456789", false);
        return;
    }
    if (kind == KB_KIND_SPEED) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_3, "0123456789.,", true);
        return;
    }
    keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_TEXT_LOWER, NULL, false);
}

void action_programs_open_keyboard_step(lv_event_t *e) {
    lv_obj_t *label = lv_event_get_target(e);
    programs_step_kb_ctx_t *ctx = (programs_step_kb_ctx_t *)lv_event_get_user_data(e);
    if (!ctx) return;

#if defined(ESP_PLATFORM)
    // #region debug-point kiln-calibration-wdt-open-keyboard
    ESP_LOGI(s_dbg_tag_kb_flow,
             "action_programs_open_keyboard_step: cur=%d target=%p step=%u kind=%d parent=%p parent_kind=%s nav=%d guard=%d",
             (int)ui_get_current_screen_id(),
             (void *)label,
             (unsigned)ctx->step,
             (int)ctx->kind,
             label ? (void *)lv_obj_get_parent(label) : NULL,
             label ? ui_debug_obj_kind(lv_obj_get_parent(label)) : "null",
             ui_is_navigation_active() ? 1 : 0,
             transient_close_guard_active() ? 1 : 0);
    // #endregion
#endif
    if (!ui_programs_screen_is_active()) {
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_kb_flow,
                 "action_programs_open_keyboard_step: skip reason=programs_inactive cur=%d nav=%d guard=%d programs_guard=%d target=%p step=%u kind=%d act=%p programs=%p",
                 (int)ui_get_current_screen_id(),
                 ui_is_navigation_active() ? 1 : 0,
                 transient_close_guard_active() ? 1 : 0,
                 programs_interaction_guard_active() ? 1 : 0,
                 (void *)label,
                 (unsigned)ctx->step,
                 (int)ctx->kind,
                 (void *)lv_scr_act(),
                 (void *)objects.programs);
#endif
        return;
    }

    s_kb_step_active = true;
    s_kb_step_idx = ctx->step;
    s_kb_step_kind = ctx->kind;

    if (ctx->kind == KB_KIND_TEMP) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_2, "0123456789", true);
        return;
    }
    if (ctx->kind == KB_KIND_HOLD) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_1, "0123456789:", true);
        return;
    }
    if (ctx->kind == KB_KIND_NUMBER) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_2, "0123456789", false);
        return;
    }
    if (ctx->kind == KB_KIND_SPEED) {
        keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_USER_3, "0123456789.,", true);
        return;
    }
    keyboard_open_for_label(label, false, LV_KEYBOARD_MODE_TEXT_LOWER, NULL, false);
}

