static void action_programs_add_step_async(void *user_data) {
    (void)user_data;
#if defined(ESP_PLATFORM)
    // #region debug-point add-step-async
    s_programs_add_step_async_ms = lv_tick_get();
    ESP_LOGI(s_dbg_tag_add_step,
             "async enter dt_from_press=%lu pending=%d",
             (unsigned long)(s_programs_add_step_press_ms ? (s_programs_add_step_async_ms - s_programs_add_step_press_ms) : 0),
             s_programs_add_step_pending ? 1 : 0);
    // #endregion
#endif
    s_programs_add_step_pending = false;

    const uint8_t pid = ui_get_selected_program_id();
    const uint8_t id = (pid == 255) ? 255 : pid;
    uint16_t cnt = ui_get_program_steps_total(id);
    if (cnt >= 20) {
        s_programs_add_step_queued = 0;
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_add_step, "async skip reason=max_steps cnt=%u", (unsigned)cnt);
#endif
        return;
    }
    if (!ui_program_add_step(id)) {
        s_programs_add_step_queued = 0;
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_add_step, "async skip reason=add_failed cnt=%u", (unsigned)cnt);
#endif
        return;
    }

#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_add_step,
             "async after_add cnt_before=%u cnt_after=%u dt_from_press=%lu",
             (unsigned)cnt,
             (unsigned)ui_get_program_steps_total(id),
             (unsigned long)(s_programs_add_step_press_ms ? (lv_tick_get() - s_programs_add_step_press_ms) : 0));
#endif

    screen_programs_refresh_rows();
    screen_programs_scroll_to_last();
    programs_update_info();
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_add_step,
             "async done total_dt=%lu queued=%u",
             (unsigned long)(s_programs_add_step_press_ms ? (lv_tick_get() - s_programs_add_step_press_ms) : 0),
             (unsigned)s_programs_add_step_queued);
#endif
    if (s_programs_add_step_queued > 0) {
        s_programs_add_step_queued--;
        s_programs_add_step_pending = true;
        action_programs_add_step_async(NULL);
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_add_step, "async queued_replay remaining=%u", (unsigned)s_programs_add_step_queued);
#endif
    }
}

void action_programs_add_step(lv_event_t *e) {
    if (e) {
        const lv_event_code_t code = lv_event_get_code(e);
        if (code != LV_EVENT_PRESSED && code != LV_EVENT_CLICKED) return;
#if defined(ESP_PLATFORM)
        // #region debug-point add-step-press
        s_programs_add_step_press_ms = lv_tick_get();
        ESP_LOGI(s_dbg_tag_add_step,
                 "press code=%d pending=%d nav=%d sel_id=%u steps=%u",
                 (int)code,
                 s_programs_add_step_pending ? 1 : 0,
                 ui_is_navigation_active() ? 1 : 0,
                 (unsigned)ui_get_selected_program_id(),
                 (unsigned)ui_get_selected_program_steps_total());
        // #endregion
#endif
    }
    if (s_programs_add_step_pending) {
        if (s_programs_add_step_queued < 3) {
            s_programs_add_step_queued++;
        }
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_add_step, "press queued reason=pending queued=%u", (unsigned)s_programs_add_step_queued);
#endif
        return;
    }
    s_programs_add_step_pending = true;
    action_programs_add_step_async(NULL);
#if defined(ESP_PLATFORM)
    ESP_LOGI(s_dbg_tag_add_step, "press handled_sync");
#endif
}

