void action_programs_save(lv_event_t *e) {
    (void)e;
    // #region debug-point program-save-time
#if defined(ESP_PLATFORM)
    s_dbg_trace_programs_update = true;
    ESP_LOGI(s_dbg_tag_program_save_time, "SAVE pressed: sel_id=%u name='%s' steps_total=%u",
             (unsigned)ui_get_selected_program_id(), ui_get_selected_program_name(), (unsigned)ui_get_selected_program_steps_total());
#endif
    // #endregion
    programs_update_info();
    uint8_t pid = ui_get_selected_program_id();
    const uint16_t steps = ui_get_selected_program_steps_total();
    if (pid == 255) {
        const char *cur_name = ui_get_selected_program_name();
        if (!cur_name || cur_name[0] == '\0' || program_name_exists(cur_name)) {
            char nm[96];
            make_default_new_program_name(nm, sizeof(nm));
            ui_set_selected_program_name(nm);
        }
        if (ui_is_programs_full()) {
            char msg[64];
            if (ui_is_english()) {
                lv_snprintf(msg, sizeof(msg), "Max %u programs (%u/%u)", (unsigned)ui_get_program_capacity(),
                            (unsigned)ui_get_program_count(), (unsigned)ui_get_program_capacity());
            } else {
                lv_snprintf(msg, sizeof(msg), "Максимум %u програм (%u/%u)", (unsigned)ui_get_program_capacity(),
                            (unsigned)ui_get_program_count(), (unsigned)ui_get_program_capacity());
            }
            toast_show(msg);
            // #region debug-point program-save-time
#if defined(ESP_PLATFORM)
            s_dbg_trace_programs_update = false;
#endif
            // #endregion
            return;
        }
        const uint8_t id = ui_add_program(ui_get_selected_program_name(), steps);
        if (id != 255) {
            programs_capture_selected(id, 255);
            pid = id;
            ui_set_selected_program_id(id);
        }
    }
    if (pid != 255) {
        ui_set_program_name(pid, ui_get_selected_program_name());
        ui_set_program_steps_total(pid, steps);
        programs_capture_selected(pid, pid);

        // #region debug-point program-save-time
#if defined(ESP_PLATFORM)
        ESP_LOGI(s_dbg_tag_program_save_time, "SAVE commit: pid=%u program_count=%u total_time_s=%lu",
                 (unsigned)pid, (unsigned)ui_get_program_count(), (unsigned long)ui_get_program_total_time_s(pid));
#endif
        // #endregion
        ui_programs_persist_save();
    }
    // #region debug-point program-save-time
#if defined(ESP_PLATFORM)
    s_dbg_trace_programs_update = false;
#endif
    // #endregion
    {
        char msg[64];
        if (ui_is_english()) {
            lv_snprintf(msg, sizeof(msg), "Saved (%u programs)", (unsigned)ui_get_program_count());
        } else {
            lv_snprintf(msg, sizeof(msg), "Збережено (%u програм)", (unsigned)ui_get_program_count());
        }
        toast_show(msg);
    }
    screen_programs_refresh_rows();
}

